mapper.insert:
	INSERT INTO TBINTRFCROUTINFODT (
		 INTRFC_ID		
		,SEQ		
		,LEN_FLD_OFFSET_LEN		
		,FLD_DATA_LEN		
		,FLD_CFG_VAL		
		,RUTNG_DESC		
		,CNDT_CD		
	) VALUES (
		 #{intrfcId, jdbcType = VARCHAR}
 		,#{seq, jdbcType = NUMERIC}
 		,#{lenFldOffsetLen, jdbcType = NUMERIC}
 		,#{fldDataLen, jdbcType = NUMERIC}
 		,#{fldCfgVal, jdbcType = VARCHAR}
 		,#{rutngDesc, jdbcType = VARCHAR}
 		,#{cndtCd, jdbcType = VARCHAR}
  	)

mapper.update:
	UPDATE TBINTRFCROUTINFODT 
	SET
		LEN_FLD_OFFSET_LEN = #{lenFldOffsetLen, jdbcType = NUMERIC}		
  		,FLD_DATA_LEN = #{fldDataLen, jdbcType = NUMERIC}		
